#include <bits/stdc++.h>
using namespace std;

// Naive recursion — exponential, for understanding only
int fib(int n) {
    if (n <= 1) return n;           // base case
    return fib(n-1) + fib(n-2);    // recursive case
}

// Memoized version — O(n)
map<int,int> memo;
int fibMemo(int n) {
    if (n <= 1) return n;
    if (memo.count(n)) return memo[n];
    return memo[n] = fibMemo(n-1) + fibMemo(n-2);
}

int main() {
    int n;
    cin >> n;
    cout << fibMemo(n) << "\n";
}

#include <bits/stdc++.h>
using namespace std;

void subsets(vector<int>& arr, int idx, vector<int>& current,
             vector<vector<int>>& result) {
    if (idx == (int)arr.size()) {
        result.push_back(current);   // base: subset is complete
        return;
    }
    // Choice 1: INCLUDE arr[idx]
    current.push_back(arr[idx]);
    subsets(arr, idx + 1, current, result);
    current.pop_back();              // UNDO (backtrack)

    // Choice 2: EXCLUDE arr[idx]
    subsets(arr, idx + 1, current, result);
}

int main() {
    int n;
    cin >> n;
    vector<int> arr(n);
    for (int& x : arr) cin >> x;

    vector<vector<int>> result;
    vector<int> current;
    subsets(arr, 0, current, result);

    cout << result.size() << "\n";   // always 2^n
    for (auto& s : result) {
        cout << "{ ";
        for (int x : s) cout << x << " ";
        cout << "}\n";
    }
}

#include <bits/stdc++.h>
using namespace std;

void permute(vector<int>& arr, vector<bool>& used,
             vector<int>& current, vector<vector<int>>& result) {
    if ((int)current.size() == (int)arr.size()) {
        result.push_back(current);
        return;
    }
    for (int i = 0; i < (int)arr.size(); i++) {
        if (used[i]) continue;
        used[i] = true;              // CHOOSE
        current.push_back(arr[i]);
        permute(arr, used, current, result);
        current.pop_back();          // UNCHOOSE
        used[i] = false;
    }
}

int main() {
    int n;
    cin >> n;
    vector<int> arr(n);
    for (int& x : arr) cin >> x;

    vector<vector<int>> result;
    vector<int> current;
    vector<bool> used(n, false);
    permute(arr, used, current, result);

    for (auto& p : result) {
        for (int x : p) cout << x << " ";
        cout << "\n";
    }
}

#include <bits/stdc++.h>
using namespace std;

void permuteSwap(vector<int>& arr, int start) {
    if (start == (int)arr.size()) {
        for (int x : arr) cout << x << " ";
        cout << "\n";
        return;
    }
    for (int i = start; i < (int)arr.size(); i++) {
        swap(arr[start], arr[i]);       // CHOOSE: fix position `start`
        permuteSwap(arr, start + 1);
        swap(arr[start], arr[i]);       // UNCHOOSE: restore
    }
}

int main() {
    int n;
    cin >> n;
    vector<int> arr(n);
    for (int& x : arr) cin >> x;
    permuteSwap(arr, 0);
}

#include <bits/stdc++.h>
using namespace std;

void combinationSum(vector<int>& cands, int idx, int remaining,
                    vector<int>& current, vector<vector<int>>& result) {
    if (remaining == 0) {
        result.push_back(current);
        return;
    }
    for (int i = idx; i < (int)cands.size(); i++) {
        if (cands[i] > remaining) break;  // PRUNE: sorted, no point continuing
        current.push_back(cands[i]);      // CHOOSE
        combinationSum(cands, i, remaining - cands[i], current, result);
        current.pop_back();               // UNCHOOSE
    }
}

int main() {
    int n, target;
    cin >> n >> target;
    vector<int> cands(n);
    for (int& x : cands) cin >> x;
    sort(cands.begin(), cands.end());  // required for pruning

    vector<vector<int>> result;
    vector<int> current;
    combinationSum(cands, 0, target, current, result);

    cout << result.size() << "\n";
    for (auto& c : result) {
        for (int x : c) cout << x << " ";
        cout << "\n";
    }
}

#include <bits/stdc++.h>
using namespace std;

void nQueens(int row, int n, vector<int>& placement,
             vector<bool>& col, vector<bool>& diag1, vector<bool>& diag2,
             int& count) {
    if (row == n) {
        count++;
        return;
    }
    for (int c = 0; c < n; c++) {
        // diag1 index = row-col+n-1 (top-left to bottom-right)
        // diag2 index = row+col      (top-right to bottom-left)
        if (col[c] || diag1[row-c+n-1] || diag2[row+c]) continue;

        col[c] = diag1[row-c+n-1] = diag2[row+c] = true;  // CHOOSE
        placement[row] = c;
        nQueens(row + 1, n, placement, col, diag1, diag2, count);
        col[c] = diag1[row-c+n-1] = diag2[row+c] = false; // UNCHOOSE
    }
}

int main() {
    int n;
    cin >> n;
    vector<int> placement(n);
    vector<bool> col(n, false);
    vector<bool> diag1(2*n-1, false), diag2(2*n-1, false);
    int count = 0;
    nQueens(0, n, placement, col, diag1, diag2, count);
    cout << count << "\n";  // number of valid placements
}

#include <bits/stdc++.h>
using namespace std;

int R, C;
vector<string> grid;
vector<vector<bool>> visited;
int pathCount = 0;

int dx[] = {0,0,1,-1};
int dy[] = {1,-1,0,0};

void dfs(int r, int c) {
    if (r == R-1 && c == C-1) {
        pathCount++;
        return;
    }
    for (int d = 0; d < 4; d++) {
        int nr = r + dx[d], nc = c + dy[d];
        if (nr<0||nr>=R||nc<0||nc>=C) continue;
        if (grid[nr][nc]=='#') continue;
        if (visited[nr][nc]) continue;
        visited[nr][nc] = true;   // CHOOSE
        dfs(nr, nc);
        visited[nr][nc] = false;  // UNCHOOSE
    }
}

int main() {
    cin >> R >> C;
    grid.resize(R);
    visited.assign(R, vector<bool>(C, false));
    for (auto& row : grid) cin >> row;
    visited[0][0] = true;
    dfs(0, 0);
    cout << pathCount << "\n";
}

#include <bits/stdc++.h>
using namespace std;

void subsetsUnique(vector<int>& arr, int idx, vector<int>& cur,
                   vector<vector<int>>& res) {
    res.push_back(cur);
    for (int i = idx; i < (int)arr.size(); i++) {
        // skip duplicate at same recursion level
        if (i > idx && arr[i] == arr[i-1]) continue;
        cur.push_back(arr[i]);
        subsetsUnique(arr, i + 1, cur, res);
        cur.pop_back();
    }
}

int main() {
    int n;
    cin >> n;
    vector<int> arr(n);
    for (int& x : arr) cin >> x;
    sort(arr.begin(), arr.end());

    vector<vector<int>> res;
    vector<int> cur;
    subsetsUnique(arr, 0, cur, res);

    for (auto& s : res) {
        for (int x : s) cout << x << " ";
        cout << "\n";
    }
}

