void perm(vector<int>& a, int s) {
    if (s == (int)a.size()) {
        for (int x : a) cout << x;
        cout << "\n";
        return;
    }
    for (int i = s; i < (int)a.size(); i++) {
        swap(a[s], a[i]);
        perm(a, s+1);
        swap(a[s], a[i]);
    }
}
