#include <bits/stdc++.h>
using namespace std;

void generate(int n, int open, int close, string& cur,
              vector<string>& result) {
    if ((int)cur.size() == 2 * n) {
        result.push_back(cur);
        return;
    }
    if (open < n) {
        cur.push_back('(');           // CHOOSE '('
        generate(n, open+1, close, cur, result);
        cur.pop_back();               // UNCHOOSE
    }
    if (close < open) {
        cur.push_back(')');           // CHOOSE ')'
        generate(n, open, close+1, cur, result);
        cur.pop_back();               // UNCHOOSE
    }
}

int main() {
    int n;
    cin >> n;
    vector<string> result;
    string cur;
    generate(n, 0, 0, cur, result);
    for (auto& s : result) cout << s << "\n";
    cout << result.size() << " combinations\n";
}

