#include <bits/stdc++.h>
using namespace std;

int n, ans = 0;
vector<vector<int>> grid;
vector<vector<bool>> vis;

void dfs(int r, int c) {
    if (r == n-1 && c == n-1) {
        ans++;
        return;
    }
    // try DOWN
    if (r+1 < n && grid[r+1][c] == 1 && !vis[r+1][c]) {
        vis[r+1][c] = true;
        dfs(r+1, c);
        vis[r+1][c] = false;
    }
    // try RIGHT
    if (c+1 < n && grid[r][c+1] == 1 && !vis[r][c+1]) {
        vis[r][c+1] = true;
        dfs(r, c+1);
        vis[r][c+1] = false;
    }
}

int main() {
    cin >> n;
    grid.assign(n, vector<int>(n));
    vis.assign(n, vector<bool>(n, false));
    for (auto& row : grid)
        for (int& x : row) cin >> x;

    if (grid[0][0] == 1 && grid[n-1][n-1] == 1) {
        vis[0][0] = true;
        dfs(0, 0);
    }
    cout << ans << "\n";
}

