#include <bits/stdc++.h>
using namespace std;

int n, target, ans = 0;
vector<int> arr;

void count(int idx, int sum) {
    if (sum == target) { ans++; return; }
    if (idx == n || sum > target) return;   // prune

    // INCLUDE arr[idx]
    count(idx + 1, sum + arr[idx]);
    // EXCLUDE arr[idx]
    count(idx + 1, sum);
}

int main() {
    cin >> n >> target;
    arr.resize(n);
    for (int& x : arr) cin >> x;
    sort(arr.begin(), arr.end());  // better pruning order
    count(0, 0);
    cout << ans << "\n";
}
